def minimax(node, maximizing=True):
    if not node['children']:
        return node['value']
    child_values = [minimax(child, not maximizing) for child in node['children']]
    if maximizing:
        return max(child_values)
    return min(child_values)

def minimax(node):
    if not node['children']:
        return node['value']
    return max(minimax(child) for child in node['children'])

import heapq

def a_star(graph, start, goal, heuristic):
    open_heap = [(heuristic(start), 0, start)]
    g_score = {start: 0}
    came_from = {}
    closed = set()
    while open_heap:
        f, g, node = heapq.heappop(open_heap)
        if node in closed:
            continue
        closed.add(node)
        if node == goal:
            path = [node]
            while path[-1] in came_from:
                path.append(came_from[path[-1]])
            path.reverse()
            return path
        for neighbour, weight in graph.get(node, []):
            tentative_g = g + weight
            if neighbour not in g_score or tentative_g < g_score[neighbour]:
                g_score[neighbour] = tentative_g
                came_from[neighbour] = node
                heapq.heappush(open_heap, (tentative_g + heuristic(neighbour), tentative_g, neighbour))
    return None
